    24→// Shared helper for recording the latest filter used.
    25→template <class Filters>
    26→void recordLatestDataFilter(typename Filters::Iterator current_filter,
    27→                            typename Filters::Element*& latest_filter, Filters& filters) {
    28→  // If this is the first time we're calling onData, just record the current filter.
    29→  if (latest_filter == nullptr) {
    30→    latest_filter = current_filter->get();
    31→    return;
    32→  }
    33→
    34→  // We want to keep this pointing at the latest filter in the filter list that has received the
    35→  // onData callback. To do so, we compare the current latest with the *previous* filter. If they
    36→  // match, then we must be processing a new filter for the first time. We omit this check if we're
    37→  // the first filter, since the above check handles that case.
    38→  //
    39→  // We compare against the previous filter to avoid multiple filter iterations from resetting the
    40→  // pointer: If we just set latest to current, then the first onData filter iteration would
    41→  // correctly iterate over the filters and set latest, but on subsequent onData iterations
    42→  // we'd start from the beginning again, potentially allowing filter N to modify the buffer even
    43→  // though filter M > N was the filter that inserted data into the buffer.
    44→  if (current_filter != filters.begin() && latest_filter == std::prev(current_filter)->get()) {
    45→    latest_filter = current_filter->get();
    46→  }
    47→}
