   193→        StreamInfo::FilterState::StateType::ReadOnly,
   194→        StreamInfo::FilterState::LifeSpan::Connection);
   195→  }
   196→
   197→  if (config_->idleTimeout()) {
   198→    connection_idle_timer_ =
   199→        dispatcher_->createScaledTimer(Event::ScaledTimerType::HttpDownstreamIdleConnectionTimeout,
   200→                                       [this]() -> void { onIdleTimeout(); });
   201→    connection_idle_timer_->enableTimer(config_->idleTimeout().value());
   202→  }
   203→
   204→  if (config_->maxConnectionDuration()) {
   205→    connection_duration_timer_ =
   206→        dispatcher_->createScaledTimer(Event::ScaledTimerType::HttpDownstreamMaxConnectionTimeout,
   207→                                       [this]() -> void { onConnectionDurationTimeout(); });
   208→    connection_duration_timer_->enableTimer(config_->maxConnectionDuration().value());
   209→  }
   210→
   211→  read_callbacks_->connection().setDelayedCloseTimeout(config_->delayedCloseTimeout());
   212→
   213→  read_callbacks_->connection().setConnectionStats(
