   814→  bool removed = false;
   815→  auto existing_active_cluster = active_clusters_.find(cluster_name);
   816→  if (existing_active_cluster != active_clusters_.end() &&
   817→      existing_active_cluster->second->added_via_api_ &&
   818→      (!existing_active_cluster->second->avoid_cds_removal_ || remove_ignored)) {
   819→    removed = true;
   820→    init_helper_.removeCluster(*existing_active_cluster->second);
   821→    active_clusters_.erase(existing_active_cluster);
   822→
   823→    ENVOY_LOG(debug, "removing cluster {}", cluster_name);
   824→    tls_.runOnAllThreads([cluster_name](OptRef<ThreadLocalClusterManagerImpl> cluster_manager) {
   825→      ASSERT(cluster_manager->thread_local_clusters_.contains(cluster_name) ||
   826→             cluster_manager->thread_local_deferred_clusters_.contains(cluster_name));
   827→      ENVOY_LOG(debug, "removing TLS cluster {}", cluster_name);
