   839→          cluster_manager->thread_local_clusters_.size());
   840→    });
   841→    cluster_initialization_map_.erase(cluster_name);
   842→  }
   843→
   844→  auto existing_warming_cluster = warming_clusters_.find(cluster_name);
   845→  if (existing_warming_cluster != warming_clusters_.end() &&
   846→      existing_warming_cluster->second->added_via_api_ &&
   847→      (!existing_warming_cluster->second->avoid_cds_removal_ || remove_ignored)) {
   848→    removed = true;
   849→    init_helper_.removeCluster(*existing_warming_cluster->second);
